css_string:
:root {
  --background: hsl(0 0% 100%);
  --foreground: hsl(0 0% 3.9%);
  --card: hsl(0 0% 100%);
  --card-foreground: hsl(0 0% 3.9%);
  --popover: hsl(0 0% 100%);
  --popover-foreground: hsl(0 0% 3.9%);
  --primary: 217.2 91.2% 59.8%;
  --primary-foreground: 0 0% 98%;
  --secondary: hsl(217.2 20% 96%);
  --secondary-foreground: hsl(217.2 45.6% 25%);
  --muted: hsl(0 0% 96.1%);
  --muted-foreground: hsl(0 0% 45.1%);
  --accent: 217.2 25% 96.1%;
  --accent-foreground: 217.2 54.72% 25%;
  --destructive: hsl(0 84.2% 60.2%);
  --destructive-foreground: hsl(0 0% 98%);
  --border: hsl(0 0% 89.8%);
  --input: hsl(0 0% 89.8%);
  --ring: hsl(217.2 91.2% 59.8%);
}

[data-theme='dark'] {
  --background: hsl(0 0% 3.9%);
  --foreground: hsl(0 0% 98%);
  --card: hsl(0 0% 3.9%);
  --card-foreground: hsl(0 0% 98%);
  --popover: hsl(0 0% 3.9%);
  --popover-foreground: hsl(0 0% 98%);
  --primary: 217.2 91.2% 65%;
  --primary-foreground: 0 0% 98%;
  --secondary: hsl(217.2 15% 18%);
  --secondary-foreground: hsl(217.2 36.480000000000004% 90%);
  --muted: hsl(0 0% 14.9%);
  --muted-foreground: hsl(0 0% 63.9%);
  --accent: 217.2 18% 14.9%;
  --accent-foreground: 217.2 45.6% 90%;
  --destructive: hsl(0 62.8% 50.6%);
  --destructive-foreground: hsl(0 0% 98%);
  --border: hsl(0 0% 14.9%);
  --input: hsl(0 0% 14.9%);
  --ring: hsl(217.2 91.2% 65%);
}
